export * as ToggleGroup from "./namespace";
export * from "./styles";
export * from "./toggle-group";

"use client";

import type { VariantProps } from "cva";
import { createContext, use } from "react";
import { ToggleButton, ToggleButtonGroup } from "react-aria-components";
import type { ToggleStyles } from "~/registry/ui/toggle";
import { ToggleGroupStyles } from "./styles";

interface ToggleGroupContextValue extends VariantProps<typeof ToggleStyles> {
  spacing?: number;
}

const ToggleGroupContext = createContext<ToggleGroupContextValue>({
  size: "default",
  variant: "default",
  spacing: 0,
});

export interface ToggleGroupRootProps
  extends React.ComponentProps<typeof ToggleButtonGroup>,
    ToggleGroupContextValue {}

export function ToggleGroupRoot({
  className,
  variant,
  size,
  spacing = 0,
  ...props
}: ToggleGroupRootProps) {
  return (
    <ToggleGroupContext.Provider value={{ variant, size, spacing }}>
      <ToggleButtonGroup
        className={ToggleGroupStyles.Root({ className })}
        data-size={size}
        data-slot="toggle-group-root"
        data-variant={variant}
        style={{ "--gap": spacing } as React.CSSProperties}
        {...props}
      />
    </ToggleGroupContext.Provider>
  );
}

export interface ToggleGroupItemProps
  extends React.ComponentProps<typeof ToggleButton>,
    VariantProps<typeof ToggleStyles> {}

export function ToggleGroupItem({
  className,
  children,
  variant,
  size,
  ...props
}: ToggleGroupItemProps) {
  const context = use(ToggleGroupContext);
  const _variant = context.variant ?? variant;
  const _size = context.size ?? size;
  const _spacing = context.spacing ?? 0;

  return (
    <ToggleButton
      className={ToggleGroupStyles.Item({
        variant: _variant,
        size: _size,
        className,
      })}
      data-size={_size}
      data-slot="toggle-group-item"
      data-spacing={_spacing}
      data-variant={_variant}
      {...props}
    >
      {children}
    </ToggleButton>
  );
}

import { compose, cva } from "~/registry/lib/cva";
import { ToggleStyles } from "../toggle/styles";

export const ToggleGroupStyles = {
  Root: cva({
    base: [
      "group/toggle-group-root flex w-fit items-center gap-[--spacing(var(--gap))] rounded-md",
      "data-[spacing=default]:data-[variant=outline]:shadow-xs",
    ],
  }),
  Item: compose(
    ToggleStyles,
    cva({
      base: [
        "min-w-0 shrink-0 px-3",
        "data-[spacing=0]:rounded-none data-[spacing=0]:shadow-none data-[spacing=0]:last:rounded-r-md data-[spacing=0]:first:rounded-l-md",
        "data-[spacing=0]:data-[variant=outline]:border-l-0 data-[spacing=0]:data-[variant=outline]:first:border-l",
      ],
    })
  ),
};

export {
  ToggleGroupItem as Item,
  ToggleGroupRoot as Root,
} from "./toggle-group";
